#!/usr/bin/env python3
"""
Golden Test Runner for Python Projects
Executes golden tests and generates JSON results
"""

import argparse
import json
import xml.etree.ElementTree as ET
from pathlib import Path
import sys
import traceback
from datetime import datetime
import importlib.util
import numpy as np

class GoldenTestRunner:
    def __init__(self, project_root=None, verbose=False):
        self.project_root = Path(project_root or '.').resolve()
        self.verbose = verbose
        self.results = {
            'project': str(self.project_root),
            'language': 'Python',
            'timestamp': datetime.now().isoformat(),
            'tests': [],
            'summary': {
                'total_tests': 0,
                'passed_tests': 0,
                'failed_tests': 0,
                'error_tests': 0,
                'skipped_tests': 0
            }
        }

    def find_test_specs(self):
        """Find all test specification files"""
        specs_dir = self.project_root / 'specs'
        if not specs_dir.exists():
            raise FileNotFoundError(f"Specs directory not found: {specs_dir}")

        return list(specs_dir.rglob('*.xml'))

    def parse_test_spec(self, spec_file):
        """Parse XML test specification"""
        tree = ET.parse(spec_file)
        root = tree.getroot()

        test = {
            'file': str(spec_file.relative_to(self.project_root)),
            'name': root.get('name', 'Unknown'),
            'description': root.find('description').text if root.find('description') is not None else '',
            'type': root.find('test_type').text if root.find('test_type') is not None else 'unit',
            'parameters': {},
            'expected_output': {},
            'tolerance': {}
        }

        # Parse parameters
        params = root.find('parameters')
        if params is not None:
            for param in params:
                test['parameters'][param.tag] = self._parse_value(param.text, param.get('type', 'string'))

        # Parse expected output
        expected = root.find('expected_output')
        if expected is not None:
            for output in expected:
                test['expected_output'][output.tag] = self._parse_value(output.text, output.get('type', 'string'))
                if output.get('tolerance'):
                    test['tolerance'][output.tag] = float(output.get('tolerance'))

        return test

    def _parse_value(self, text, dtype):
        """Parse value based on type"""
        if text is None:
            return None

        text = text.strip()

        if dtype == 'int':
            return int(text)
        elif dtype == 'float':
            return float(text)
        elif dtype == 'bool':
            return text.lower() in ('true', '1', 'yes')
        elif dtype == 'array':
            # Parse array values
            values = text.replace('[', '').replace(']', '').split(',')
            return [float(v.strip()) for v in values if v.strip()]
        else:
            return text

    def execute_test(self, test_spec):
        """Execute a single test"""
        result = {
            'name': test_spec['name'],
            'file': test_spec['file'],
            'status': 'passed',
            'message': '',
            'actual_output': {},
            'expected_output': test_spec['expected_output'],
            'execution_time': 0
        }

        start_time = datetime.now()

        try:
            # Import the module being tested
            # For now, we'll try to import common HRF functions
            if 'hrf' in test_spec['name'].lower():
                try:
                    # Try to import from various possible locations
                    from pyfmrihrf import hrf
                    module = hrf
                except ImportError:
                    try:
                        import hrf
                        module = hrf
                    except ImportError:
                        # Create a mock module for testing
                        module = self._create_mock_hrf_module()

            # Extract function name from test name
            func_name = self._extract_function_name(test_spec['name'])

            if hasattr(module, func_name):
                func = getattr(module, func_name)

                # Execute function with parameters
                params = test_spec['parameters']
                if params:
                    result['actual_output']['value'] = func(**params)
                else:
                    result['actual_output']['value'] = func()

                # Compare with expected output
                self._compare_outputs(result, test_spec)

            else:
                result['status'] = 'error'
                result['message'] = f"Function '{func_name}' not found in module"

        except Exception as e:
            result['status'] = 'error'
            result['message'] = str(e)
            result['traceback'] = traceback.format_exc()

        result['execution_time'] = (datetime.now() - start_time).total_seconds()
        return result

    def _extract_function_name(self, test_name):
        """Extract function name from test name"""
        # Common patterns in test names
        if test_name.startswith('hrf_'):
            return test_name[4:]  # Remove 'hrf_' prefix
        elif '_hrf_' in test_name:
            parts = test_name.split('_hrf_')
            return parts[0]
        else:
            # Use the test name as is
            return test_name.lower().replace(' ', '_')

    def _create_mock_hrf_module(self):
        """Create a mock HRF module for testing"""
        class MockHRF:
            @staticmethod
            def spmg1_basic(**kwargs):
                """Mock SPM canonical HRF"""
                tr = kwargs.get('tr', 2.0)
                duration = kwargs.get('duration', 32)
                t = np.arange(0, duration, tr)
                # Simple gamma function approximation
                return np.exp(-t/6) * (t**5) / 120

            @staticmethod
            def gamma_hrf(**kwargs):
                """Mock Gamma HRF"""
                tr = kwargs.get('tr', 2.0)
                duration = kwargs.get('duration', 32)
                t = np.arange(0, duration, tr)
                return np.exp(-t/6) * (t**5) / 120

        return MockHRF()

    def _compare_outputs(self, result, test_spec):
        """Compare actual output with expected output"""
        for key, expected in test_spec['expected_output'].items():
            if key not in result['actual_output']:
                result['status'] = 'failed'
                result['message'] = f"Missing output key: {key}"
                return

            actual = result['actual_output'][key]
            tolerance = test_spec['tolerance'].get(key, 1e-6)

            if isinstance(expected, (list, np.ndarray)) and isinstance(actual, (list, np.ndarray)):
                if not np.allclose(actual, expected, rtol=tolerance, atol=tolerance):
                    result['status'] = 'failed'
                    result['message'] = f"Array mismatch for {key}"
            elif isinstance(expected, (int, float)) and isinstance(actual, (int, float)):
                if abs(actual - expected) > tolerance:
                    result['status'] = 'failed'
                    result['message'] = f"Value mismatch for {key}: expected {expected}, got {actual}"
            else:
                if actual != expected:
                    result['status'] = 'failed'
                    result['message'] = f"Value mismatch for {key}: expected {expected}, got {actual}"

    def run_all_tests(self):
        """Run all tests and generate results"""
        test_specs = self.find_test_specs()
        self.results['summary']['total_tests'] = len(test_specs)

        if self.verbose:
            print(f"Found {len(test_specs)} test specifications")

        for spec_file in test_specs:
            if self.verbose:
                print(f"Running test: {spec_file.name}")

            try:
                test_spec = self.parse_test_spec(spec_file)
                result = self.execute_test(test_spec)
                self.results['tests'].append(result)

                # Update summary
                if result['status'] == 'passed':
                    self.results['summary']['passed_tests'] += 1
                elif result['status'] == 'failed':
                    self.results['summary']['failed_tests'] += 1
                elif result['status'] == 'error':
                    self.results['summary']['error_tests'] += 1
                else:
                    self.results['summary']['skipped_tests'] += 1

                if self.verbose:
                    print(f"  Status: {result['status']}")
                    if result['message']:
                        print(f"  Message: {result['message']}")

            except Exception as e:
                if self.verbose:
                    print(f"  Error parsing test spec: {e}")
                self.results['summary']['error_tests'] += 1

        return self.results

    def save_results(self, output_file):
        """Save results to JSON file"""
        with open(output_file, 'w') as f:
            json.dump(self.results, f, indent=2)

        if self.verbose:
            print(f"\nResults saved to: {output_file}")
            print(f"Summary: {self.results['summary']['passed_tests']}/{self.results['summary']['total_tests']} passed")


def main():
    parser = argparse.ArgumentParser(description='Run golden tests for Python project')
    parser.add_argument('--project', default='.', help='Project root directory')
    parser.add_argument('--output', default=None, help='Output JSON file')
    parser.add_argument('--verbose', action='store_true', help='Verbose output')

    args = parser.parse_args()

    runner = GoldenTestRunner(project_root=args.project, verbose=args.verbose)
    results = runner.run_all_tests()

    if args.output:
        runner.save_results(args.output)
    else:
        # Generate timestamped filename
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        output_file = f"golden_test_results_python_{timestamp}.json"
        runner.save_results(output_file)

    # Exit with error code if tests failed
    if results['summary']['failed_tests'] > 0 or results['summary']['error_tests'] > 0:
        sys.exit(1)
    else:
        sys.exit(0)


if __name__ == '__main__':
    main()

